#include <iostream>
#include <fstream>
#include <vector>
#include <string>
#include <cstring>
#include <cassert>
#include <cmath>
#include "MdfFormat.h"
#include "json.hpp"

using json = nlohmann::json;

static json Float2ToJson(const Float2 &v) {
    return json::array({v.x, v.y});
}

static json Float3ToJson(const Float3 &v) {
    return json::array({v.x, v.y, v.z});
}

static json Float4ToJson(const Float4 &v) {
    return json::array({v.x, v.y, v.z, v.w});
}

static json MatrixToJson(const TMdfMatrix4 &m) {
    json arr = json::array();
    for (int i = 0; i < 16; ++i) arr.push_back(m.e[i]);
    return arr;
}

int main(int argc, char** argv) {
    if (argc != 3) {
        std::cerr << "Usage: " << argv[0] << " <input.mdf> <output.json>" << std::endl;
        return 1;
    }
    const char* inputPath = argv[1];
    const char* outputPath = argv[2];

    MdfFormat mdf;
    if (!mdf.CreateFromFile(inputPath)) {
        std::cerr << "Failed to load MDF file: " << inputPath << std::endl;
        return 1;
    }

    json j;
    // Header
    const MdfHeader &header = mdf.GetHeader();
    j["header"]["version"] = std::string(header.cId, 8);
    j["header"]["meshCount"] = header.nMeshCount;
    j["header"]["animCount"] = header.nAnimCount;
    j["header"]["textureCount"] = header.nTextureCount;
    j["header"]["byteAlignment"] = header.nByteAlignment;
    j["header"]["totalDataSize"] = header.nTotalDataSize;

    // Textures
    json textures = json::array();
    for (unsigned int i = 0; i < mdf.GetNumTextures(); ++i) {
        textures.push_back(mdf.GetTextureName(i));
    }
    j["textures"] = textures;

    // Meshes
    json meshes = json::array();
    for (unsigned int i = 0; i < mdf.GetNumMeshes(); ++i) {
        const TMdfMesh &mesh = mdf.GetMesh(i);
        json m;
        m["vertexCount"] = mesh.nNumVerts;
        m["indexCount"] = mesh.nNumIndices;
        m["jointCount"] = mesh.nNumJoints;
        m["textureIndex"] = mesh.hTexture;
        m["type"] = (mesh.nNumJoints > 0) ? "skinned" : "static";

        // Vertices
        json vertices = json::array();
        if (mesh.nNumJoints > 0) {
            // Skinned vertices
            const TMdfVertSkn *verts = static_cast<const TMdfVertSkn*>(mesh.uVtxs.pVertices);
            for (unsigned int v = 0; v < mesh.nNumVerts; ++v) {
                json vert;
                vert["position"] = Float3ToJson(verts[v].pos);
                vert["weights"] = json::array({verts[v].weights[0], verts[v].weights[1], verts[v].weights[2]});
                vert["bones"] = json::array({verts[v].bones[0], verts[v].bones[1], verts[v].bones[2], verts[v].bones[3]});
                vert["normal"] = Float3ToJson(verts[v].normal);
                vert["texcoord"] = Float2ToJson(verts[v].texcoord);
                vertices.push_back(vert);
            }
        } else {
            // Static vertices
            const TMdfVertSta *verts = static_cast<const TMdfVertSta*>(mesh.uVtxs.pVertices);
            for (unsigned int v = 0; v < mesh.nNumVerts; ++v) {
                json vert;
                vert["position"] = Float3ToJson(verts[v].pos);
                vert["normal"] = Float3ToJson(verts[v].normal);
                vert["texcoord"] = Float2ToJson(verts[v].texcoord);
                vertices.push_back(vert);
            }
        }
        m["vertices"] = vertices;

        // Indices
        json indices = json::array();
        const unsigned short *idx = mesh.uIdxs.pIndices;
        for (unsigned int idxIdx = 0; idxIdx < mesh.nNumIndices; ++idxIdx) {
            indices.push_back(idx[idxIdx]);
        }
        m["indices"] = indices;

        // Bind pose and parent info (if skinned)
        if (mesh.nNumJoints > 0) {
            json bindPose = json::array();
            const TMdfMatrix4 *matrices = mesh.uBnd.pBindMats;
            for (unsigned int j = 0; j < mesh.nNumJoints; ++j) {
                bindPose.push_back(MatrixToJson(matrices[j]));
            }
            m["bindPose"] = bindPose;

            json parentInfo = json::array();
            const int *parents = mesh.uPrnt.pParentInfo;
            for (unsigned int j = 0; j < mesh.nNumJoints; ++j) {
                parentInfo.push_back(parents[j]);
            }
            m["parentInfo"] = parentInfo;
        }

        meshes.push_back(m);
    }
    j["meshes"] = meshes;

    // Animations
    json animations = json::array();
    for (unsigned int i = 0; i < mdf.GetNumAnimations(); ++i) {
        const TMdfAnimation &anim = mdf.GetAnimation(i);
        json a;
        a["meshId"] = anim.hMeshId;
        a["timelineCount"] = anim.nNumTimelines;
        a["duration"] = anim.fTimeLength;
        json timelines = json::array();
        for (int t = 0; t < anim.nNumTimelines; ++t) {
            const TMdfTimeline &tl = anim.uTls.pTimeline[t];
            json timeline;
            timeline["keyframeCount"] = tl.nKeyFrames;
            json keyframes = json::array();
            for (int k = 0; k < tl.nKeyFrames; ++k) {
                const TMdfKeyframe &kf = tl.uKfs.pKeyframes[k];
                json keyframe;
                keyframe["time"] = kf.fKeyTime;
                keyframe["translation"] = Float3ToJson(kf.vecTranslation);
                keyframe["rotation"] = Float4ToJson(kf.qRotation);
                keyframe["scale"] = Float3ToJson(kf.vecScale);
                keyframes.push_back(keyframe);
            }
            timeline["keyframes"] = keyframes;
            timelines.push_back(timeline);
        }
        a["timelines"] = timelines;
        animations.push_back(a);
    }
    j["animations"] = animations;

    // Write JSON
    std::ofstream out(outputPath);
    out << j.dump(4) << std::endl;
    return 0;
}
EOF
