#include <cstring>
#include <cassert>
#include <cmath>
#include "MdfFormat.h"
#include <nlohmann/json.hpp>

using json = nlohmann::json;

static json Float2ToJson(const Float2 &v) {
    return json::array({v.x, v.y});
}

static json Float3ToJson(const Float3 &v) {
    return json::array({v.x, v.y, v.z});
}

static json Float4ToJson(const Float4 &v) {
    return json::array({v.x, v.y, v.z, v.w});
}

static json MatrixToJson(const TMdfMatrix4 &m) {
    json arr = json::array();
    for (int i = 0; i < 16; ++i) arr.push_back(m.e[i]);
    return arr;
}

std::vector<std::string> ReadTextureNames(const char* filename, unsigned int textureCount) {
    std::vector<std::string> result;
    if (textureCount == 0) return result;
    std::ifstream file(filename, std::ios::binary);
    if (!file) return result;
    // Skip header (32 bytes)
    file.seekg(32);
    // Read texture offsets (each 4 bytes)
    std::vector<uint32_t> offsets(textureCount);
    file.read(reinterpret_cast<char*>(offsets.data()), textureCount * sizeof(uint32_t));
    for (uint32_t off : offsets) {
        file.seekg(off);
        std::string str;
        std::getline(file, str, '\0');
        result.push_back(str);
    }
    return result;
}

