    j["header"]["version"] = std::string(header.cId, 8);
    j["header"]["meshCount"] = header.nMeshCount;
    j["header"]["animCount"] = header.nAnimCount;
    j["header"]["textureCount"] = header.nTextureCount;
    j["header"]["byteAlignment"] = header.nByteAlignment;
    j["header"]["totalDataSize"] = header.nTotalDataSize;

    // Textures - read directly from file
    auto textures = ReadTextureNames(inputPath, header.nTextureCount);
    j["textures"] = textures;

    // Meshes
    json meshes = json::array();
    for (unsigned int i = 0; i < mdf.GetNumMeshes(); ++i) {
        const TMdfMesh &mesh = mdf.GetMesh(i);
        json m;
        m["vertexCount"] = mesh.nNumVerts;
        m["indexCount"] = mesh.nNumIndices;
        m["jointCount"] = mesh.nNumJoints;
        m["textureIndex"] = mesh.hTexture;
        m["type"] = (mesh.nNumJoints > 0) ? "skinned" : "static";

        // Vertices
